<template>
    <div class="musiDiv0" id="musiDivz"> 
      <div class="div-volume-z">
        <div class="div-volume">
          <div class="block" >
            <el-slider v-model="musicVolumeValue" @change="mvch"></el-slider>
          </div> 
        </div>
      </div>
      <musicV class="musicv" :unicon="false" v-for="i in musicList " :key="i.id" :musicData='i' :musicVolumeValue='musicVolumeValue' ref="mz"></musicV>
    </div>
</template>

<script>
import musicV from './music.vue';
export default {
  name: 'mucisControl',
  components: {
    musicV
  },
  data() {
    return {
        musicVolumeValue:this.$store.state.musicVolumeValue,
        musicList:[
            {
                id:"0mC",
                mp3Src:'100',
            },
            {
                id:"1mC",
                mp3Src:'200',
            },
            {
                id:"2mC",
                mp3Src:'300',
            },
            {
                id:"3mC",
                mp3Src:'400',
            },
            {
                id:"4mC",
                mp3Src:'500',
            },
            {
                id:"5mC",
                mp3Src:'600',
            },
            {
                id:"6mC",
                mp3Src:'700',
            },
            {
                id:"7mC",
                mp3Src:'800',
            },
        ],

    };
  },
  methods: {
    mvch() {
      this.$store.dispatch('musicVolumeValueChange',this.musicVolumeValue);
    },
  },
  mounted(){
    this.$bus.$on('mStop',(id)=>{
      this.$refs.mz.forEach((the)=>{
          if(id!=the.musicData.id){
            the.$refs.audio1.pause();
          }
      })
    })
    document.addEventListener('keydown',(event)=>{
      switch(event.code){
        case 'ArrowUp':if(this.musicVolumeValue<100)this.musicVolumeValue+=2;this.mvch(); break;
        case 'ArrowDown':if(this.musicVolumeValue>0)this.musicVolumeValue-=2;this.mvch(); break;
      }
    });
  }
}
</script>

<style scoped>
  .musiDiv0{
    position: relative;
    margin-top: 70px;
    display: flex;
    justify-content: center;
    /* border: 1px solid red; */
    flex-wrap:wrap;
    width: 90vw;
    
  }
  .musicv{
    margin: 8px;
    width: 19vw;
    height: 19vw;
  }
  .div-volume-z{
    position: fixed;
    display: flex;
    right: 3%;
    top: 13px;
    z-index: 10;
  }
  .div-volume{
    width:80px;
  }

    
</style>

<style>
  #musiDivz .el-slider__bar{
    background-color: #67C23A;
  }
  #musiDivz .el-slider__button{
      border:2px solid #67C23A;
      width: 13px;
      height: 13px;
  }
</style>