import Vue from 'vue';
import Vuex from 'vuex';
Vue.use(Vuex)

const actions ={
    flageChange:function(context,value){
        context.commit('Flagechange',value)
    },
    musicVolumeValueChange:function(context,value){
        context.commit('MusicVolumeValueChange',value)
    },
    activitiesHistoryChange:function(context,value){
        context.commit('ActivitiesHistoryChange',value)
    },
    activitiesSayingChange:function(context,value){
        context.commit('ActivitiesSayingChange',value)
    },
    hisFlageChange:function(context){
        context.commit('HisFlageChange')
    },
    drawListChange:function(context,value){
        context.commit('DrawListchange',value)
    },
}

const mutations={
    Flagechange:function(state,value){
        state.flage=value;   
    },
    MusicVolumeValueChange:function(state,value){
        state.musicVolumeValue=value;   
    },
    ActivitiesHistoryChange:function(state,value){
        state.activitiesHistory=value;   
    },
    ActivitiesSayingChange:function(state,value){
        state.activitiesSaying=value;   
    },
    HisFlageChange:function(state){
        state.hisFlage=!state.hisFlage;   
    },
    DrawListchange:function(state,value){
        state.drawList=value;   
    },
}

const state={
    flage:true,
    hisFlage:true,
    musicVolumeValue:30,
    activitiesHistory:1,
    activitiesSaying:1,
    drawList:null,
}

export default new Vuex.Store({
    actions,
    mutations,
    state
})