<template>
  <div class="div0" id="yueHistory">
    <div class="history">
      <div class="divRadio">
        <el-radio-group v-model="reverse">
          <el-radio :label="true">倒序</el-radio>
          <el-radio :label="false">正序</el-radio>
        </el-radio-group>
        <div class="swidchDiv">
        <el-switch
          style="display: block"
          v-model="flagehis"
          active-color="#13ce66"
          inactive-color="#ff4949" 
          disabled
          @click.native='switchOpen'
          >
        </el-switch> 
        </div>
      </div>
      <el-timeline :reverse="reverse">
          <el-timeline-item placement="top" 
            v-for="activity in activities"
            :key="activity.ids"
            type="success"
            size="large"
            :timestamp="activity.timestamp">
            <el-card>
                <div class="divCardT">
                  <h3>{{activity.text}}</h3>
                </div>
                <div v-if="activity.mvData">
                <musicV class="musicVDiv" :musicData='JSON.parse(activity.mvData)' :musicVolumeValue='musicVolumeValue' ref="mzz" :unicon="true"></musicV>
                </div>
                <div class="divA" v-if="activity.vided">
                  <el-link type="info" class="ellink" v-for="(i,index) in videdJson(activity.vided)" :key="i" :href="i" :underline="false" target="_Blank">{{index}}</el-link>
                </div>
            </el-card>
          </el-timeline-item>
      </el-timeline>
    </div>
    <div class="divDatas" >
      <img class="imgLihui" src="https://s2.loli.net/2022/04/17/qrcNiQWk2gn39Fa.png" alt="">
      <div class="divIntrouce1">
        <span>原本住在与人类世界间有结界的偏远的精灵村，有一天因为送一个偶然迷路至此的人类小孩儿回人类世界而意外接触网络，从此沉迷人类流行文化并从遥远的山林深处跨越[gate]来到人类世界。母语是性精灵语，擅长汉语和日语，英语有中学生水平，同时在学西班牙语和荷兰语。是Wactor的清楚担当(自称)。</span>
      </div>
      <div class="divIntrouce2">
        <span>右手缠有绷带，本人称其中封印者可以改变世界的力量，如果到了要解开绷带的地步，说明世界发生了需要使用右手力量的时候。</span>
      </div>
      <div class="divIntrouce3">
        <span>佐保姬夕映</span>
        <span>サオヒメユエ</span>
        <span>SaohimeYue</span>
      </div>
      <div class="line">
        <a target="_Blank" href="https://www.youtube.com/channel/UCIm8pnnTNhCgGAtNxrQQv-g" class="youtub"></a>
        <a target="_Blank" href="https://twitter.com/SaohimeYue" class="tuite"></a>
        <a target="_Blank" href="https://space.bilibili.com/1923344666/" class="bilibili"></a>
      </div>
    </div>
    <div class="div-volume">
      <div class="block"  >
        <el-slider v-if="!flagehis" v-model="musicVolumeValue" @change="mvch"></el-slider>
      </div> 
    </div>
  </div>
</template>

<script>
import musicV from './music.vue';
import hisCheckbox from './hisCheckbox.vue'
export default {
 
  name: 'yuehistory',
  components:{
    musicV,
    // hisCheckbox
  },
  data() {
    return {
      switchOpenFlage:true,
      // activitiesTimes:'',
      flagehis:this.$store.state.flage,
      musicVolumeValue:this.$store.state.musicVolumeValue,
      reverse: true,
      activitiesHistory: [],
      activitiesSaying: [],

      activities: [{
        ids:'1ss',
        timestamp:'',
        text:'加载中' 
      }],
      nullMusicData:{
        id:'',
        mp3Src:'',
        imgSrc:'',
      },
      nullvideData:{
        'src1':''
      }
    };
  },
  watch:{
    flagehis:function(){
      this.$store.dispatch('flageChange',this.flagehis);
      this.activitiesChange();
    }
  },
  methods: {
    mvch() {
      this.$store.dispatch('musicVolumeValueChange',this.musicVolumeValue);
    },
    videdJson(k){
      if(k!=null){
        return JSON.parse(k);
      }
      else{
        return this.nullvideData;
      }
    },
    activitiesChange(){
      if(this.flagehis){
        this.activities=this.activitiesHistory;
      }
      else{
        this.activities=this.activitiesSaying;
      }
    },
    switchOpen() {
      if(this.switchOpenFlage){
        const h = this.$createElement;
        this.$messageBox({
          title: '警告',
          message: h('p', null, [
            h('span', { style: 'color: teal' }, '此操作将切换模式，home，biography页面内容将出现变化，是否继续? '),
            h(hisCheckbox, null, "")
          ]),
          showCancelButton: true,
          confirmButtonText: '确定',
          cancelButtonText: '取消',
        }).then(() => {
          this.flagehis=!this.flagehis;
          if(this.flagehis){
            this.$message({
              type: 'success',
              message: '已退出里模式'
            });
          }
          else{
            this.$message({
              type: 'warning',
              message: '已进入里模式'
            });
          }
        })
        .catch(() => {
          // this.$message({
          //   type: 'info',
          //   message: '已取消模式转换'
          // });          
        });
      }
      else{
        this.flagehis=!this.flagehis;
      }
    },
    activitiesGet(){
      if(this.$store.state.activitiesHistory!=1&&this.$store.state.activitiesSaying!=1){
        if(this.$store.state.activitiesHistory!=''&&this.$store.state.activitiesSaying!=''){
          this.activitiesHistory=this.$store.state.activitiesHistory;
          this.activitiesSaying=this.$store.state.activitiesSaying;
          this.activitiesChange();
        }
        else{
          this.$bus.$emit('getAxiosB');
        }
      }
    }

  },
  mounted(){
    if(localStorage.getItem('openFlage')!=null){
      this.switchOpenFlage =!JSON.parse(localStorage.getItem('openFlage'));
    }
    this.activitiesGet();
    this.$bus.$on('activitiesGetA',this.activitiesGet);

      
    
    this.$bus.$on('mStop2',(id)=>{
      this.$refs.mzz.forEach((the)=>{
          if(id!=the.musicData.id){
            the.$refs.audio1.pause();
          }
      })
    })

    this.$bus.$on('switchOpenFlageC',()=>{
      this.switchOpenFlage=!JSON.parse(localStorage.getItem('openFlage'));
    })
  }
}
</script>

