<template>
  <div>
    <el-checkbox v-model="checked" @change="change">勾选下次不再弹出提示</el-checkbox>
  </div>
</template>

<script>
  export default {
    name: 'hisCheckbox',
    data() {
      return {
        checked: JSON.parse(localStorage.getItem('openFlage')),
      };
    },
    methods:{
      change(){
        localStorage.setItem('openFlage', this.checked);
        this.$bus.$emit('switchOpenFlageC');
      }
    },
  };
</script>

