import Vue from 'vue'
import App from './App.vue'
import VueRouter from 'vue-router'
import router from './router'
import store from './store'
import VueParticles from 'vue-particles'  
import { Divider,Progress,Link,Notification,Checkbox, MessageBox ,Message,Button,Timeline,Icon,Slider,Menu,Submenu,MenuItem,MenuItemGroup,Card,TimelineItem,RadioGroup,Radio,Pagination,Switch} from 'element-ui';
import Unicon from 'vue-unicons/dist/vue-unicons-vue2.umd'
import {  uniExpandArrowsAlt,uniMultiply,uniSpinnerAlt,uniVolume } from 'vue-unicons/dist/icons'


 





Vue.config.productionTip = false
Unicon.add([uniVolume,uniSpinnerAlt,uniMultiply,uniExpandArrowsAlt])
Vue.use(Unicon)
Vue.use(VueRouter)
Vue.use(VueParticles)   
Vue.component(Button.name, Button);
Vue.component(Timeline.name,Timeline);
Vue.component(Icon.name,Icon);
Vue.component(Slider.name,Slider);
Vue.component(Menu.name,Menu);
Vue.component(Submenu.name,Submenu);
Vue.component(MenuItem.name,MenuItem);
Vue.component(MenuItemGroup.name,MenuItemGroup);
Vue.component(Card.name,Card);
Vue.component(TimelineItem.name,TimelineItem);
Vue.component(RadioGroup.name,RadioGroup);
Vue.component(Radio.name,Radio);
Vue.component(Pagination.name,Pagination);
Vue.component(Switch.name,Switch);
Vue.component(Checkbox.name,Checkbox);
Vue.component(Link.name,Link);
Vue.component(Progress.name,Progress);
Vue.component(Divider.name,Divider);




new Vue({
  render: h => h(App),
  router:router,
  store:store,
  beforeCreate(){
    Vue.prototype.$bus =this;
    Vue.prototype.$message = Message;
    Vue.prototype.$messageBox = MessageBox;
    Vue.prototype.$notification = Notification;
  }
}).$mount('#app')
