        <a v-if="vestC5!=null" :href="vestC5" target="_Blank"><h3>画师传送门</h3></a>
        
      </div>
      <div class="div-f" @click="vestFlage=!vestFlage" ref="multi" >
        <unicon name="multiply" fill="limegreen" width="100%" height="100%" :style="rotateStyle"></unicon>
      </div>
    </div>
    
    <div class="div1">
      <div class="div1-1">
        <div class="div1-123-z" v-for="i in imgList[0]" :key="i.id" @click="detail(i)">
          <img :src="i.imgSrc" alt="loading..." > 
          <div class="div-but">
            <div class="dd"><unicon name="expand-arrows-alt" fill="#de5d83" width="31px" height="31px"></unicon></div>
          </div>
        </div>
      </div>
        
      <div class="div1-2">
        <div class="div1-123-z" v-for="i in imgList[1]" :key="i.id" @click="detail(i)">
          <img :src="i.imgSrc" alt="loading..." >
          <div class="div-but">
            <div class="dd"><unicon name="expand-arrows-alt" fill="#de5d83" width="31px" height="31px"></unicon></div>
          </div> 
        </div>
      </div>

      <div class="div1-3">
        <div class="div1-123-z" v-for="i in imgList[2]" :key="i.id" @click="detail(i)">
          <img :src="i.imgSrc" alt="loading..."  > 
          <div class="div-but">
            <div class="dd"><unicon name="expand-arrows-alt" fill="#de5d83" width="31px" height="31px"></unicon></div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'lunBoTu',

  data() {
    return {
      vestFlage:false,
      rotates:0,
      vestSrc:'#',
      vestC1:null,
      vestC2:null,
      vestC3:null,
      vestC4:null,
      vestC5:null,
      imgList:'',

    };
  },
  computed: {
    rotateStyle:function(){
      return {transform: `rotate(${this.rotates}deg)`}
    }
  },
  methods: {
    detail(i){
      this.vestSrc=i.imgSrc;
      this.vestC1=i.offer;
      this.vestC2=i.author;
      this.vestC3=i.authoro;
      this.vestC4=i.addres;
      this.vestC5=i.autadd;
      
      this.vestFlage=!this.vestFlage;
    },
    cssCh1(){
      this.rotates=180;
    },
    cssCh2(){
      this.rotates=0;
    },

    getIList(){
      if(this.$store.state.drawList==null){
        this.$bus.$emit('getDrawList');
        // console.log('200');
      }
      else{
        this.imgList=this.$store.state.drawList;
        // console.log('300');
      }
    }
  },
  mounted () {
    this.$bus.$on('getIList',this.getIList);
    this.getIList();
    this.$refs.multi.addEventListener('mouseover',this.cssCh1);
    this.$refs.multi.addEventListener('mouseout',this.cssCh2);
    
  },
  beforeDestroy(){
    this.$refs.multi.removeEventListener('mouseover',this.cssCh1);
    this.$refs.multi.removeEventListener('mouseout',this.cssCh2);
  }
}
</script>


