<template>
  <div id="app">
    <el-menu  :default-active="activeIndex" class="el-menu-demo" mode="horizontal"  active-text-color="#13ce66">
      <el-menu-item index="home"  @click="goHome" >HOME</el-menu-item>
      <el-menu-item index="biography"  @click="goHsitory" >BIOGRAPHY</el-menu-item>
      <el-menu-item index="media"  @click="goTu">DRAW</el-menu-item>
      <el-submenu index="game">
        <template slot="title">GAME</template>
        <el-menu-item index="gameCat"  @click="goGameCat">CAT</el-menu-item>
      </el-submenu>
      <el-menu-item index="thanks"  @click="goThanks">THANKS</el-menu-item>
    </el-menu>
    <div class="divRouter" >
      <vue-particles
        color="#67C23A"
        :particleOpacity="1"
        :particlesNumber="42"
        shapeType="star"
        :particleSize="8"
        linesColor="#67C23A"
        :linesWidth="1"
        :lineLinked="true"
        :lineOpacity="0.4"
        :linesDistance="160"
        :moveSpeed="3"
        :hoverEffect="true"
        hoverMode="grab"
        :clickEffect="true"
        clickMode="push"
        class="lizi"
      >
      </vue-particles>
      <router-view ></router-view>
      
      <div class="divlod" v-if="dcf">
        <div  class="divlodc">
          <img src="https://s2.loli.net/2022/04/13/wNxfsJByTru9PI4.png" alt="">
          <div class="divdc">
            <el-progress :text-inside="true" :stroke-width="24" :percentage="proVa" status="success"></el-progress>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import axios from 'axios';

export default {
  name: 'App',
  data() {
    return {
      activeIndex: this.$route.name,
      proVa:0,
      dcf:true,
      tiot:''
    };
  },
  methods: {
    goHome(){
      this.$router.push({ name:'home'})
    },
    goTu(){
      this.$router.push({ name:'media'})
    },
    goHsitory(){
      this.$router.push({ 
        name:'biography',
      });
    },
    goGameCat(){
      this.$router.push({ name:'gameCat'})
    },
    goThanks(){
      this.$router.push({ name:'thanks'})
    },

    getDrawList(re){
      // console.log('3');
      axios.get(require('../public/aixosUrlList.js').axiosUrlList[2])
      .then(res => {
        let zlist = []
        res.data.forEach((value) => {
          delete value.id;
          for (let i in value){
            if(value[i]!=null){
              value[i]=JSON.parse(value[i]);
            }
            else{
              delete value[i];
            }
          }
          zlist.push(value)
        });
        this.$store.dispatch('drawListChange', zlist);
        this.proVa=90;
        this.$bus.$emit('getIList');
        if(re!=null){
          re();
        }
        
      })
      .catch(err => {
        console.error(err);
        this.$store.dispatch('drawListChange','err');
        this.$bus.$emit('getIList');
        this.proVa=90;
        if(re!=null){
          re();
        }
      });
    },

    getBiu(re){
      let gA0 = new Promise((resolve)=>{
        // console.log("1");
        axios.get(require('../public/aixosUrlList.js').axiosUrlList[0])
        .then(res => {
          this.$store.dispatch('activitiesHistoryChange',res.data);
          resolve();
          this.proVa=30;
        })
        .catch(err => {
          console.error(err); 
          this.$store.dispatch('activitiesHistoryChange',
          [{
            id:1,
            timestamp:'警告',
            text:'服务器宕机'
          }]); 
          resolve();
          this.proVa=30;
        })
      })
      gA0.then(()=>{
          // console.log("2");
          axios.get(require('../public/aixosUrlList.js').axiosUrlList[1])
          .then(res => {
            this.$store.dispatch('activitiesSayingChange',res.data);
            this.$bus.$emit('activitiesGetA');
            // console.log(res.data);
            this.proVa=60;
            if(re!=null){
              re();
            }
          })
          .catch(err => {
            console.error(err);
            this.$bus.$emit('activitiesGetA'); 
            this.$store.dispatch('activitiesSayingChange',
            [{
              id:'1s',
              timestamp:'警告',
              text:'服务器宕机'
            }]);
            this.proVa=60;
            if(re!=null){
              re();
            }
          });
        })
    },

    getAxiosZ(){
      let a1 =new Promise((resolve)=>{
        this.getBiu(resolve);
      })
      a1.then(()=>{
        return new Promise((resolve)=>{
          this.getDrawList(resolve);
        }) 
      })
      .then(()=>{
        this.proVa=100;
        // console.log('zzz');
        this.tiot=setTimeout(()=>{
          this.dcf=false;
          clearTimeout(this.tiot);
        },3000);
      })
    },
    
  },
  mounted () {
    this.getAxiosZ();
    this.$bus.$on('getAxiosB',this.getBiu);
    this.$bus.$on('getDrawList',this.getDrawList);

  }
}
</script>

