import VueRouter from 'vue-router'
import lunBoTu from '../components/lunBoTu.vue'
import yuehistory from '../components/yuehistory.vue'
import mucisControl from '../components/mucisControl.vue'
import home from '../components/home.vue'
// import articles from '../components/articles.vue'
import thanks from '../components/thanks.vue'

export default new VueRouter({
    routes:[
        {
            name:'media',
            path:'/media',
            component:lunBoTu
        },
        {
            name:'biography',
            path:'/biography/',
            // path:'/biography/h/s',
            component:yuehistory
        },
        {
            name:'gameCat',
            path:'/gameCat',
            component:mucisControl
        },
        {
            name:'home',
            path:'/home',
            component:home
        },
        {
            name:'thanks',
            path:'/thanks',
            component:thanks
        }
    ]
})