<template>
  <div class="musicDiv0">
    <audio ref="audio1" :src="mp3Src" controls="controls"></audio>
    <div class="div1-border">
      <div class="div1-filter " @click="musicPlay" >
        <!-- <img class="div1-img1" :src="musicData.imgSrc" alt="" v-if="musicData.imgSrc"> -->
        <unicon name="volume" fill="limegreen" width=100% height=100%  v-if="unicon" v-show="!uniconSc"></unicon>
        <unicon name="spinner-alt" fill="limegreen" :width="spinnerWidth" :height="spinnerHeight" class="unicoLoda" v-if="uniconSc"></unicon>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'music',
  props:['musicData','musicVolumeValue','unicon'],
  data() {
    return {
      musicVolumeValueScoped:this.musicVolumeValue,
      musicScheduleValue:0,
      uniconSc:false,
      spinnerWidth:"40%",
      spinnerHeight:"40%"
    };
  },
  watch:{
    musicVolumeValue:function(){
      this.musicVolumeValueScoped=this.musicVolumeValue;
      this.musicVolume();
    }
  },
  computed:{
    mp3Src:function(){
      if(this.musicData!=null)
        return `${require('../../public/aixosUrlList').axiosUrlList[3]}?number=${this.musicData.mp3Src}`;
      else
        return null;
    }
  },
  methods:{
    musicPlay(){
      if(this.unicon){
        this.$bus.$emit('mStop2',this.musicData.id); 
      }
      else{
        this.$bus.$emit('mStop',this.musicData.id); 
      }
      this.musicScheduleValue=0;
      this.musicSchedule();
      this.$refs.audio1.play();
      //点击播放，二次点击关闭
      // if(this.$refs.audio1.paused){
        
      //   this.$refs.audio1.play();
      // }
      // else{
      //   2 用于按钮点击后归零音频进度
      //   this.musicScheduleValue=0;
      //   this.musicSchedule();
      //   this.$refs.audio1.pause();
      // } 
    }, 
    musicSchedule(){
      
    },
    musicVolume(){
      this.$refs.audio1.volume=this.musicVolumeValue*0.01;
    },

    // musOpen() {
    //   this.$notification({
    //     title: `音频第${this.musicData.id}位加载失败`
    //   });
    // },
    musictimeupdate(){
      this.musicScheduleValue = this.$refs.audio1.currentTime*100/this.$refs.audio1.duration;
    },

    loadedmetadatafun(){
      this.$refs.audio1.addEventListener('timeupdate',this.musictimeupdate)
      this.musicSchedule=()=>{
        this.$refs.audio1.currentTime=this.$refs.audio1.duration*this.musicScheduleValue*0.01;
      }
    },
    waitingfun(){
      this.uniconSc=true;
    },
    canplaythroughfun(){
      this.uniconSc=false;
    }

  },
  mounted () {
      this.musicVolume()
      this.$refs.audio1.addEventListener('loadedmetadata',this.loadedmetadatafun)
      // this.$refs.audio1.addEventListener('error',this.musOpen)
      this.$refs.audio1.addEventListener('waiting',this.waitingfun)
      this.$refs.audio1.addEventListener('canplaythrough',this.canplaythroughfun)

      if(this.unicon){
        this.spinnerWidth="90%",
        this.spinnerHeight="90%"
      }
     
  },
  beforeDestroy(){
    this.$refs.audio1.removeEventListener('loadedmetadata',this.loadedmetadatafun)
    this.$refs.audio1.removeEventListener('timeupdate',this.musictimeupdate)
    // this.$refs.audio1.removeEventListener('error',this.musOpen)
    this.$refs.audio1.removeEventListener('waiting',this.waitingfun)
    this.$refs.audio1.removeEventListener('canplaythrough',this.canplaythroughfun)

  }
}
</script>


<style scoped>
  audio{
    display: none;
  }
  @keyframes example {
    from {transform: rotate(0deg);}
    to {transform: rotate(360deg)}
  }
  .div1-border{
    width: 100%;
    height: 100%;
    box-shadow: 0px 0px 5px 3px rgba(255, 255, 255, 0.5)  inset;
    box-shadow: 0px 0px 5px 1px rgba(0, 0, 0, 0.2)  ;
  }
  .div1-border:active{
    box-shadow: 0px 0px 5px 3px rgba(255, 255, 255, 0.5)  inset;
    box-shadow: 0px 0px 1px 1px rgba(0, 0, 0, 0.1)  ;
  }
  .div1-filter{
    width: 100%;
    height: 100%;
    background-color: rgba(247, 247, 247, 0) ;
    backdrop-filter: blur(3px) ;
    display: flex;
    justify-content: center;
    align-items: center;
  }
  .div1-img1{
    width: 80%;
    height: 80%;
    object-fit:cover;
    margin-top: 10%;
  }
  .unicoLoda{
    animation-name: example;
    animation-duration: 4s;
    animation-iteration-count: infinite;
  }
  .unicon{
    position: absolute;
    width:80%; 
    height:80%;
    display: flex;
    justify-content: center;
    align-items: center;
  }
  .el-button--success{
    color: #67C23A;
  }
  .el-slider__bar{
    background-color: #67C23A;
  }
  .el-slider__button{
      border:2px solid #67C23A;
      width: 13px;
      height: 13px;
  }
  .el-icon-video-pause{
    font-size: 45px
  }
  .el-icon-video-play{
    font-size: 45px;
  }
  .el-button{
    background: rgb(255, 255, 255,0);
    border: 1px solid rgb(255, 255, 255,0);
  }
  .el-icon-headset{
    font-size: 20px;
  }
</style>


